import { chromium } from 'playwright';
import { readFileSync } from 'fs';

const COOKIE_FILE = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';
const TARGET_DEST = '1v1_test';
const MAX_WAIT_SECONDS = 600; // 10 minutes
const POLL_INTERVAL_MS = 10000; // 10 seconds

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function main() {
  console.log('[INFO] Reading cookies...');
  const cookies = JSON.parse(readFileSync(COOKIE_FILE, 'utf-8'));

  console.log('[INFO] Launching browser (headless)...');
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();

  // Add cookies
  await context.addCookies(cookies.map(c => ({
    name: c.name,
    value: c.value,
    domain: c.domain,
    path: c.path,
    httpOnly: c.httpOnly || false,
    secure: c.secure || false,
    sameSite: c.sameSite || 'Lax',
  })));

  const page = await context.newPage();

  try {
    // Step 1: Verify cookie - navigate to pipeline page
    console.log('[STEP 1] Navigating to pipeline page...');
    await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });

    const currentUrl = page.url();
    console.log(`[STEP 1] Current URL: ${currentUrl}`);

    if (currentUrl.includes('login') || currentUrl.includes('auth') || currentUrl.includes('signin')) {
      throw new Error('Cookie expired or invalid - redirected to login page');
    }

    console.log('[STEP 1] ✅ Cookie is valid. Logged in successfully.');

    // Take a screenshot for debugging
    await page.screenshot({ path: 'pipeline_step1_page.png', fullPage: false });
    console.log('[STEP 1] Screenshot saved to pipeline_step1_page.png');

    // Step 2: Trigger pipeline
    console.log('[STEP 2] Looking for "启动新构建" button...');

    // Try multiple selector strategies
    let triggerBtn = null;
    const selectors = [
      'button:text("启动新构建")',
      'button:text("新构建")',
      'a:text("启动新构建")',
      'a:text("新构建")',
      'button:has-text("启动")',
      'button:has-text("新构建")',
      '[class*="trigger"]',
      '[class*="build"] button',
      '.pipeline-trigger-btn',
    ];

    for (const sel of selectors) {
      triggerBtn = await page.$(sel);
      if (triggerBtn) {
        console.log(`[STEP 2] Found button with selector: ${sel}`);
        break;
      }
    }

    if (!triggerBtn) {
      // Try to find any button that looks relevant
      const allButtons = await page.$$('button');
      console.log(`[STEP 2] Found ${allButtons.length} buttons on page`);
      for (const btn of allButtons) {
        const text = await btn.textContent();
        console.log(`[STEP 2] Button text: "${text}"`);
        if (text && (text.includes('启动') || text.includes('构建') || text.includes('新建'))) {
          triggerBtn = btn;
          console.log(`[STEP 2] Found matching button with text: "${text}"`);
          break;
        }
      }
    }

    if (!triggerBtn) {
      // Print page content for debugging
      const bodyText = await page.textContent('body');
      console.log('[STEP 2] Page body text (first 2000 chars):', bodyText.substring(0, 2000));
      // Take screenshot
      await page.screenshot({ path: 'pipeline_step2_debug.png', fullPage: true });

      // Try clicking via page.evaluate
      console.log('[STEP 2] Trying JavaScript click via evaluate...');
      const clicked = await page.evaluate(() => {
        const buttons = document.querySelectorAll('button');
        for (const btn of buttons) {
          if (btn.textContent.includes('启动') || btn.textContent.includes('新构建')) {
            btn.click();
            return true;
          }
        }
        return false;
      });
      if (clicked) {
        console.log('[STEP 2] Clicked button via evaluate()');
        await sleep(2000);
      } else {
        throw new Error('Could not find "启动新构建" button');
      }
    } else {
      await triggerBtn.click();
      console.log('[STEP 2] Clicked "启动新构建" button');
      await sleep(2000);
    }

    await page.screenshot({ path: 'pipeline_step2_after_click.png', fullPage: false });
    console.log('[STEP 2] Screenshot after click saved');

    // Step 3: Find and change dest parameter
    console.log(`[STEP 3] Looking for dest parameter (target: ${TARGET_DEST})...`);

    // Try to find the dest input/select
    let destChanged = false;

    // Method 1: Look for select elements with dest option
    const selects = await page.$$('select');
    console.log(`[STEP 3] Found ${selects.length} select elements`);
    for (const sel of selects) {
      const name = await sel.getAttribute('name');
      const id = await sel.getAttribute('id');
      const label = await page.evaluate(el => {
        const lbl = document.querySelector(`label[for="${el.id}"]`);
        return lbl ? lbl.textContent : '';
      }, sel);

      console.log(`[STEP 3] Select: name="${name}", id="${id}", label near="${label}"`);

      const innerHtml = await sel.innerHTML();
      if (innerHtml.includes('1v1') || innerHtml.includes('test') || innerHtml.includes('dest')) {
        console.log(`[STEP 3] Found matching select, selecting ${TARGET_DEST}...`);
        await sel.selectOption(TARGET_DEST);
        destChanged = true;
        console.log(`[STEP 3] Selected ${TARGET_DEST}`);
        break;
      }
    }

    // Method 2: Look for input fields
    if (!destChanged) {
      const inputs = await page.$$('input');
      console.log(`[STEP 3] Found ${inputs.length} input elements`);
      for (const input of inputs) {
        const placeholder = await input.getAttribute('placeholder');
        const name = await input.getAttribute('name');
        const id = await input.getAttribute('id');
        const type = await input.getAttribute('type');
        console.log(`[STEP 3] Input: name="${name}", id="${id}", type="${type}", placeholder="${placeholder}"`);

        if ((placeholder && placeholder.includes('dest')) || 
            (name && name.includes('dest')) || 
            (id && id.includes('dest'))) {
          console.log(`[STEP 3] Found dest input, filling ${TARGET_DEST}...`);
          await input.fill(TARGET_DEST);
          destChanged = true;
          break;
        }
      }
    }

    // Method 3: Look for any input/select labeled "dest" or "目标"
    if (!destChanged) {
      console.log('[STEP 3] Looking for dest parameter by label text...');
      await page.screenshot({ path: 'pipeline_step3_form.png', fullPage: false });

      const labels = await page.$$('label');
      for (const label of labels) {
        const text = await label.textContent();
        console.log(`[STEP 3] Label text: "${text}"`);
      }

      // Try using evaluate to find dest
      const found = await page.evaluate((target) => {
        // Look for selects with options containing 1v1
        const selects = document.querySelectorAll('select');
        for (const sel of selects) {
          const options = Array.from(sel.options);
          if (options.some(o => o.value.includes('1v1') || o.text.includes('1v1'))) {
            sel.value = target;
            sel.dispatchEvent(new Event('change', { bubbles: true }));
            return { method: 'select', name: sel.name || sel.id };
          }
        }

        // Look for inputs
        const inputs = document.querySelectorAll('input');
        for (const inp of inputs) {
          const placeholder = inp.placeholder || '';
          const name = inp.name || '';
          const id = inp.id || '';
          const text = (placeholder + name + id).toLowerCase();
          if (text.includes('dest') || text.includes('目标') || text.includes('服')) {
            const nativeInputValueSetter = Object.getOwnPropertyDescriptor(
              window.HTMLInputElement.prototype, 'value'
            ).set;
            nativeInputValueSetter.call(inp, target);
            inp.dispatchEvent(new Event('input', { bubbles: true }));
            inp.dispatchEvent(new Event('change', { bubbles: true }));
            return { method: 'input', name: inp.name || inp.id };
          }
        }

        return null;
      }, TARGET_DEST);

      if (found) {
        destChanged = true;
        console.log(`[STEP 3] Changed dest via evaluate(): ${JSON.stringify(found)}`);
      }
    }

    if (!destChanged) {
      console.log('[STEP 3] ⚠️ Could not find dest parameter. Will try to submit with defaults and continue.');
      // Take a screenshot to help debug
      await page.screenshot({ path: 'pipeline_step3_no_dest.png', fullPage: true });
    } else {
      console.log(`[STEP 3] ✅ Dest set to ${TARGET_DEST}`);
    }

    await sleep(1000);

    // Step 4: Submit the form
    console.log('[STEP 4] Looking for submit/confirm button...');

    const submitSelectors = [
      'button:text("确定")',
      'button:text("提交")',
      'button:text("确认")',
      'button:text("开始构建")',
      'button:text("运行")',
      'button:text("执行")',
      'button:text("启动")',
      'button[type="submit"]',
      '.ant-btn-primary',
      '[class*="submit"]',
      '[class*="confirm"]',
    ];

    let submitBtn = null;
    for (const sel of submitSelectors) {
      submitBtn = await page.$(sel);
      if (submitBtn) {
        console.log(`[STEP 4] Found submit button with selector: ${sel}`);
        break;
      }
    }

    if (!submitBtn) {
      // Try to find any button in a dialog/modal
      const allButtons = await page.$$('button');
      console.log(`[STEP 4] All buttons found: ${allButtons.length}`);
      for (const btn of allButtons) {
        const text = await btn.textContent();
        const isVisible = await btn.isVisible();
        console.log(`[STEP 4] Button: "${text}" visible=${isVisible}`);
        if (text && isVisible && (text.includes('确定') || text.includes('提交') || text.includes('确认') || text.includes('运行') || text.includes('执行'))) {
          submitBtn = btn;
          console.log(`[STEP 4] Found submit button with text: "${text}"`);
          break;
        }
      }
    }

    if (!submitBtn) {
      // Try clicking via evaluate
      await page.screenshot({ path: 'pipeline_step4_no_submit.png', fullPage: true });

      const clicked = await page.evaluate(() => {
        const buttons = document.querySelectorAll('button');
        for (const btn of buttons) {
          const text = btn.textContent || '';
          if (text.includes('确定') || text.includes('提交') || text.includes('确认') || text.includes('运行') || text.includes('执行')) {
            if (btn.offsetParent !== null) { // is visible
              btn.click();
              return text;
            }
          }
        }
        // Try .ant-btn-primary
        const primaryBtn = document.querySelector('.ant-btn-primary');
        if (primaryBtn) {
          primaryBtn.click();
          return 'primary-btn';
        }
        return null;
      });

      if (clicked) {
        console.log(`[STEP 4] Clicked button via evaluate(): "${clicked}"`);
        await sleep(3000);
      } else {
        throw new Error('Could not find submit/confirm button');
      }
    } else {
      await submitBtn.click();
      console.log('[STEP 4] Clicked submit button');
      await sleep(3000);
    }

    // Wait for navigation/form submission
    await page.waitForLoadState('networkidle', { timeout: 15000 }).catch(() => {});
    await page.screenshot({ path: 'pipeline_step4_submitted.png', fullPage: false });
    console.log('[STEP 4] Form submitted');

    // Step 5: Wait for pipeline to complete
    console.log(`[STEP 5] Waiting for pipeline to complete (max ${MAX_WAIT_SECONDS}s)...`);

    const startTime = Date.now();
    let completed = false;
    let result = 'unknown';

    while (Date.now() - startTime < MAX_WAIT_SECONDS * 1000) {
      await sleep(POLL_INTERVAL_MS);

      // Reload the page to get latest status
      await page.reload({ waitUntil: 'networkidle', timeout: 30000 });

      const bodyText = await page.textContent('body');

      console.log(`[STEP 5] Polling... elapsed: ${((Date.now() - startTime) / 1000).toFixed(0)}s`);

      // Check for completion indicators
      if (bodyText.includes('成功') || bodyText.includes('Succeeded') || bodyText.includes('completed')) {
        result = 'success';
        completed = true;
        console.log('[STEP 5] ✅ Pipeline appears to have succeeded');
        break;
      }

      if (bodyText.includes('失败') || bodyText.includes('Failed') || bodyText.includes('error') || bodyText.includes('Error')) {
        result = 'failure';
        completed = true;
        console.log('[STEP 5] ❌ Pipeline appears to have failed');
        break;
      }

      // Check if still running
      if (bodyText.includes('运行中') || bodyText.includes('Running') || bodyText.includes('pending') || bodyText.includes('Pending')) {
        console.log('[STEP 5] Still running...');
        continue;
      }

      // Take a screenshot every poll for debugging
      await page.screenshot({ path: `pipeline_poll_${Math.floor((Date.now() - startTime) / 1000)}s.png`, fullPage: false });
    }

    if (!completed) {
      console.log('[STEP 5] ⏰ Timeout reached. Pipeline did not complete within the expected time.');
      result = 'timeout';
    }

    // Final screenshot
    await page.screenshot({ path: 'pipeline_final_state.png', fullPage: true });

    // Return result
    return {
      success: result === 'success',
      status: result,
      url: page.url(),
    };

  } catch (error) {
    console.error(`[ERROR] ${error.message}`);
    await page.screenshot({ path: 'pipeline_error.png', fullPage: true }).catch(() => {});
    return {
      success: false,
      status: 'error',
      error: error.message,
    };
  } finally {
    await browser.close();
    console.log('[INFO] Browser closed');
  }
}

main().then(result => {
  console.log('\n========== FINAL RESULT ==========');
  console.log(JSON.stringify(result, null, 2));
  console.log('==================================\n');
  process.exit(result.success ? 0 : 1);
});

