import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ viewport: { width: 1920, height: 1080 } });
await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a', { waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
await page.waitForTimeout(3000);

// Check form elements
const result = await page.evaluate(() => {
    const inputs = document.querySelectorAll('input');
    const forms = document.querySelectorAll('form');
    const buttons = document.querySelectorAll('button, a.btn, a[href*="lark"]');
    const socialLinks = document.querySelectorAll('[class*="social"] a, [id*="social"] a, .social-providers a');

    const inputInfo = Array.from(inputs).map(i => ({
        type: i.type,
        name: i.name,
        id: i.id,
        placeholder: i.placeholder || '',
    }));

    const buttonInfo = Array.from(buttons).map(b => ({
        text: (b.textContent || '').trim().substring(0, 50),
        href: b.href || '',
        class: b.className || '',
    }));

    return {
        formCount: forms.length,
        inputs: inputInfo,
        buttons: buttonInfo,
        socialLinks: Array.from(socialLinks).map(a => ({
            text: (a.textContent || '').trim().substring(0, 50),
            href: a.href || '',
        })),
        bodyText: document.body.innerText.substring(0, 2000),
    };
});

console.log('Login Page Analysis:');
console.log(JSON.stringify(result, null, 2));

await page.screenshot({ path: 'devops_login_page_full.png', fullPage: true });
console.log('Screenshot saved');

await browser.close();

