// Refresh DevOps cookie by logging in through Feishu SSO
// This script starts in headed mode so the user can scan QR code if needed
import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';

const WORKSPACE_DIR = 'C:\\Users\\yyzypublic\\.openclaw\\workspace';
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const STATE_FILE = path.join(WORKSPACE_DIR, 'memory', 'devops-keepalive-state.json');
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

function writeState(state) {
  try {
    fs.mkdirSync(path.dirname(STATE_FILE), { recursive: true });
    fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
  } catch (e) {
    console.error('Failed to write state:', e.message);
  }
}

async function main() {
  console.log('[INFO] Starting cookie refresh via Feishu SSO...');

  // Try headless first to see if Feishu auto-logs in
  let browser = await chromium.launch({ 
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  const page = await ctx.newPage();

  try {
    // Step 1: Go to DevOps URL (will redirect to Keycloak login)
    console.log('[1/5] Navigating to DevOps pipeline page...');
    await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2000);
    console.log(`URL: ${page.url()}`);

    // Step 2: Click Feishu login button
    console.log('[2/5] Clicking "通过 飞书 登录"...');
    const larkBtn = await page.$('.zocial.lark, a[href*="lark"]');
    if (!larkBtn) {
      throw new Error('Could not find Feishu login button');
    }

    // Navigate to Feishu OAuth URL
    const larkUrl = await larkBtn.getAttribute('href');
    console.log(`Feishu OAuth URL: ${larkUrl}`);

    // Click the button
    await Promise.all([
      page.waitForNavigation({ waitUntil: 'networkidle', timeout: 15000 }).catch(() => {}),
      larkBtn.click(),
    ]);

    console.log(`After Feishu click URL: ${page.url()}`);
    await page.waitForTimeout(3000);

    // Check if we got redirected to Feishu OAuth / QR code page
    const currentUrl = page.url();
    console.log(`Current URL: ${currentUrl}`);

    // Check for Feishu QR code page or auto-redirect
    const bodyText = await page.textContent('body');
    console.log('Page text (first 500):', bodyText.substring(0, 500));

    // If we're back at DevOps (authed), save cookies
    if (currentUrl.includes('devops.devcloud.ztgame.com') && !currentUrl.includes('auth') && !currentUrl.includes('login')) {
      console.log('[3/5] ✅ Auto-logged in via Feishu!');
      const newCookies = await ctx.cookies();
      fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
      console.log(`✅ Saved ${newCookies.length} cookies to ${COOKIES_FILE}`);

      writeState({
        ok: true,
        at: new Date().toISOString(),
        cookieCount: newCookies.length,
        method: 'feishu_auto',
      });

      await browser.close();
      console.log('[DONE] Cookie refreshed successfully');
      process.exit(0);
    }

    // If it's a QR code page, switch to headed mode
    console.log('[3/5] Feishu requires QR scan. Switching to headed mode...');
    await browser.close();

    // Launch in headed mode
    browser = await chromium.launch({ 
      headless: false,
      args: ['--no-sandbox'],
    });
    const ctx2 = await browser.newContext({
      locale: 'zh-CN',
      viewport: { width: 1200, height: 900 },
      ignoreHTTPSErrors: true,
    });
    const page2 = await ctx2.newPage();

    console.log('[4/5] Opening DevOps login page in headed mode...');
    await page2.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });

    // Click Feishu login
    const larkBtn2 = await page2.$('.zocial.lark, a[href*="lark"]');
    if (larkBtn2) {
      await larkBtn2.click();
      console.log('Clicked Feishu login, waiting for QR scan...');
    }

    // Wait for user to scan QR code and login (up to 120 seconds)
    console.log('[5/5] Waiting for QR code scan (120s timeout)...');
    let loggedIn = false;
    for (let i = 0; i < 120; i++) {
      await new Promise(r => setTimeout(r, 1000));
      try {
        const url = page2.url();
        if (url.includes('devops.devcloud.ztgame.com') && !url.includes('auth') && !url.includes('login')) {
          loggedIn = true;
          console.log(`✅ Logged in! URL: ${url}`);
          break;
        }
      } catch (e) {
        // Page might be loading
      }
      if (i % 10 === 0) console.log(`  Waiting... ${i}s`);
    }

    if (!loggedIn) {
      console.log('❌ Login timeout. User did not scan QR code.');
      await browser.close();
      process.exit(1);
    }

    // Save cookies
    await page2.waitForTimeout(2000);
    const newCookies = await ctx2.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    console.log(`✅ Saved ${newCookies.length} cookies to ${COOKIES_FILE}`);

    writeState({
      ok: true,
      at: new Date().toISOString(),
      cookieCount: newCookies.length,
      method: 'feishu_qr_scan',
    });

    await browser.close();
    console.log('[DONE] Cookie refreshed successfully via QR scan');
    process.exit(0);

  } catch (error) {
    console.error(`[ERROR] ${error.message}`);
    writeState({ ok: false, error: error.message, at: new Date().toISOString() });
    try { await browser.close(); } catch {}
    process.exit(1);
  }
}

main();

