import fs from 'fs';
import path from 'path';

const WORKSPACE_DIR = 'C:\\Users\\yyzypublic\\.openclaw\\workspace';
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const STATE_FILE = path.join(WORKSPACE_DIR, 'memory', 'devops-keepalive-state.json');
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

async function main() {
  console.log('[INFO] Starting cookie refresh via Feishu (trying account login)...');

  const browser = await chromium.launch({ 
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  const page = await ctx.newPage();
  page.setDefaultTimeout(30000);

  try {
    // Step 1: Navigate to DevOps
    console.log('[1/5] Navigating to DevOps pipeline page...');
    await page.goto(PIPELINE_URL, { waitUntil: 'networkidle' });
    console.log(`URL: ${page.url()}`);

    // Step 2: Click Feishu login
    console.log('[2/5] Clicking "通过 飞书 登录"...');
    await page.click('.zocial.lark, a[href*="lark"]');
    await page.waitForLoadState('networkidle');
    console.log(`URL: ${page.url()}`);

    // Step 3: On Feishu login page - check if there's an account login option
    await page.waitForTimeout(2000);

    // Check what's on the page
    const pageInfo = await page.evaluate(() => {
      const links = Array.from(document.querySelectorAll('a'));
      const buttons = Array.from(document.querySelectorAll('button, div[role="button"], span[role="button"]'));
      const allClickable = [...links, ...buttons].map(el => ({
        tag: el.tagName,
        text: (el.textContent || '').trim().substring(0, 80),
        href: el.href || '',
        className: el.className || '',
      }));

      // Find all input fields
      const inputs = Array.from(document.querySelectorAll('input, [contenteditable="true"]')).map(i => ({
        placeholder: i.placeholder || '',
        type: i.type || '',
        name: i.name || '',
        id: i.id || '',
      }));

      return {
        title: document.title,
        clickableElements: allClickable,
        inputs,
        text: document.body.innerText.substring(0, 2000),
      };
    });

    console.log('Feishu login page info:');
    console.log('Title:', pageInfo.title);
    console.log('Inputs:', JSON.stringify(pageInfo.inputs));
    console.log('Clickable elements with text:', JSON.stringify(pageInfo.clickableElements.filter(e => e.text)));

    await page.screenshot({ path: 'feishu_login_page.png', fullPage: true });
    console.log('Screenshot saved');

    // Step 4: Look for "账号登录" link/button and click it
    const accountLoginBtn = await page.$('a:has-text("账号登录"), button:has-text("账号登录"), span:has-text("账号登录"), div:has-text("账号登录"), [class*="account"] a, a[href*="account"]');

    if (accountLoginBtn) {
      console.log('[3/5] Found "账号登录" button, clicking...');
      await accountLoginBtn.click();
      await page.waitForTimeout(2000);

      const afterClick = await page.evaluate(() => ({
        url: location.href,
        inputs: Array.from(document.querySelectorAll('input')).map(i => ({
          placeholder: i.placeholder,
          type: i.type,
          name: i.name,
        })),
        text: document.body.innerText.substring(0, 1000),
      }));
      console.log('After account login click:', JSON.stringify(afterClick));
      await page.screenshot({ path: 'feishu_account_login.png', fullPage: true });
    } else {
      console.log('[3/5] No "账号登录" found, page might already be on account login');
    }

    await browser.close();
    console.log('[DONE]');

  } catch (error) {
    console.error(`[ERROR] ${error.message}`);
    try { await page.screenshot({ path: 'feishu_error.png' }).catch(() => {}); } catch {}
    try { await browser.close(); } catch {}
  }
}

main();

